mapper.select:
SELECT
FROM common_code code WHERE 1=1
AND code.group_code = #{groupCode}
AND code.code_name LIKE '%' || #{codeName} || '%'
AND code.use_yn = #{useYn}
ORDER BY code.group_code ASC, code.sort_index ASC

SELECT

FROM common_code code
WHERE code.group_code = #{groupCode}
AND code.code = #{code}

mapper.update:
UPDATE common_code

    code_name = #{codeName},
    use_yn = #{useYn},
    description = #{description},
    sort_index = #{sortIndex},
    mod_date = CURRENT_TIMESTAMP,
    mod_user_key = #{modUserKey}

WHERE group_code = #{groupCode}
AND code = #{code}

mapper.delete:
DELETE
FROM common_code
WHERE group_code = #{groupCode}
  AND code = #{code}

mapper.select:
SELECT COUNT(*)
FROM common_code code
WHERE 1=1

    AND code.group_code = #{groupCode}


    AND code.code_name LIKE '%' || #{codeName} || '%'


    AND code.use_yn = #{useYn}

SELECT *
FROM common_code code
WHERE 1=1

    AND code.group_code = #{groupCode}


    AND code.code_name LIKE '%' || #{codeName} || '%'


    AND code.use_yn = #{useYn}

ORDER BY code.reg_date DESC
LIMIT #{pageSize} OFFSET #{offset}
